import{_ as a,o as e,c as p,a3 as t}from"./chunks/framework.BjwLbrw5.js";const r="/img.png",l="/img_1.png",_=JSON.parse('{"title":"Выбор стека технологий (доступность и поддерживаемость)","description":"","frontmatter":{"title":"Выбор стека технологий (доступность и поддерживаемость)","date":"2022-12-24T00:00:00.000Z","permalink":"/stack-2"},"headers":[],"relativePath":"posts/2022-12-24-stack-2-maintainability-reliability.md","filePath":"posts/2022-12-24-stack-2-maintainability-reliability.md"}'),s={name:"posts/2022-12-24-stack-2-maintainability-reliability.md"};function o(n,i,c,d,g,h){return e(),p("div",null,[...i[0]||(i[0]=[t('<p>Это вторая статья в цикле &quot;Выбор стека технологий&quot;.</p><p><a href="/stack-1.html">1. Выбор стека технологий (введение и кейсы)</a></p><p>В первой статье мы определили содержание стека технологий. Это:</p><ul><li>хранилище данных</li><li>бэкенд-фреймворк</li><li>фронтенд-фреймворк</li><li>системы виртуализации/контейнеризации</li><li>DevOps (IaC, мониторинг, логгирование), например, ELK (Elasticsearch, Logstash, Kibana)</li></ul><hr><h2 id="доступность-reliability" tabindex="-1">Доступность (reliability) <a class="header-anchor" href="#доступность-reliability" aria-label="Permalink to &quot;Доступность (reliability)&quot;">​</a></h2><p>Доступность измеряется отношением общества количества запросов к количеству неответов.</p><p>Вернемся к кейсам и ранжируем их по требованиям к надежности:</p><p>EdTech - SLA 99.999% прописано в контракте (5 минут в год на обслуживание)</p><p>HR-Tech - business-critical, SLA 99.99%</p><p>PropTech - 2 часа offline в неделю, при том, что это PWA вполне допустимо.</p><p>FinTech - консоль SaaS будет использоваться раз в месяц, даже если пролежит неделю - не критично</p><p>Blog - мой блог лежал полгода и переезжал с домена на домен, самый менее критичный продукт с требованием к персистентности больше чем к доступности</p><p>По стеку что выбрано в результате и на ходу:</p><p>EdTech - Postgres, Java 17 Spring Boot, Low-Code, Next.js (SSG+Nginx), Tailwind, отдельный человек-SRE (Docker, minio, Yandex Cloud Kubernetes) - с появлением Java 19, пророчу Java долгую, но сложную жизнь</p><p>HR-Tech - Postgres, Java microservices, Angular 1X, Kafka, Shared SRE (0.3 FTE)</p><p>PropTech - MongoDB, Redis, Nest.js, React, no devops - MongoDB падает на 200 пользователях, переписать на Postgres - полгода работы пары человек минимум</p><p>FinTech - .Net Core (потому что Azure AD), Angular</p><p>Blog - GitHub Pages, VuePress, Markdown</p><p>По факту, как ни смешно, самым надежным оказался блог на GitHub Pages. Простота = надежность.</p><p>На других проектах DevOps-практика подкачала, деплои были большей частью ручные, а релизы - нестабильные.</p><p>Вывод - доступность приложения целиком и полностью зависит от Ops и инфраструктуры. Это база, которая закладывается на старте проекта.</p><p>Поэтому если доступность одно из требований, уже при инициализации проекта должны быть настроены бэкапы и восстановление, мониторинг, система оповещений об инцидентах, пайплайн поставок, тестовые стенды и простейшие автотесты.</p><p>Здесь мой выбор пал на GitLab, Jenkins и AWS. Ввиду отсутствия альтернатив. В случае российских проектов, Yandex Cloud достаточно production-ready с отзывчивой поддержкой.</p><h2 id="поддерживаемость" tabindex="-1">Поддерживаемость <a class="header-anchor" href="#поддерживаемость" aria-label="Permalink to &quot;Поддерживаемость&quot;">​</a></h2><p>По стандарту ISO/IEC 25010 поддерживаемость - набор атрибутов, содержащих необходимые усилия для внесения изменений.</p><p>Чтобы что-то изменить, это нужно - проанализировать, изменить, отладить и протестировать.</p><p><img src="'+r+'" alt="img.png"></p><p>Как человек, проведший огромное количество времени за реверс-инженерией legacy-кода, я ставлю этот атрибут вторым параметром в уравнение поиска идеального стека.</p><p>Java 19 догнал в развитии Elixir/Erlang спустя 30 лет этой гонки.</p><p>Тем не менее, поддерживаемым код паралельных процессов и всего остального на Java назвать сложно.</p><p>Недаром в последнем опросе пользовательских предпочтений StackOverflow, Elixir на втором месте.</p><p>Если бы проекты можно было писать без оглядки на рынок, я бы взял для бэкенда Elixir. Ибо любой разработчик поймет код который на нем написан. И сможет писать на нем уже через пару недель. А вот с Java не так.</p><p>Elixir это не только синтаксис, сколько среда выполнения, обратите внимание на табличку ниже из книги Elixir in Action: <img src="'+l+'" alt="img_1.png"></p><p>Несмотря на то, что Elixir медленнее компилируемых языков, в плане реализации высокодоступных систем ему нет равных.</p><p>Поэтому если бы я выбирал стек технологий снова, он был бы таким:</p><p>EdTech - Postgres, Phoenix LiveView, Tailwind</p><p>HR-Tech - Postgres, Phoenix LiveView, Kafka</p><p>PropTech - просто убрал бы пересчет аналитики в транзакции, JS-стек стартапу подошел хорошо</p><p>FinTech - .Net Core (потому что Azure AD), Angular - по-другому никак</p><p>Blog - GitHub Pages, VuePress, Markdown - идеально</p>',41)])])}const m=a(s,[["render",o]]);export{_ as __pageData,m as default};
